CREATE TABLE IF NOT EXISTS market_placements(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),submission_id text NOT NULL,placement_number varchar(100) NOT NULL UNIQUE,carrier varchar(100) NOT NULL,carrier_account_manager varchar(100),carrier_email varchar(255),carrier_phone varchar(20),coverage_types jsonb,requested_limits jsonb,special_requirements text,carrier_appetite varchar(20),status varchar(20) NOT NULL DEFAULT 'submitted',submitted_date timestamptz NOT NULL DEFAULT now(),acknowledged_date timestamptz,expected_quote_date timestamptz,quote_received_date timestamptz,decline_date timestamptz,bound_date timestamptz,carrier_decline_reason text,carrier_feedback text,assigned_agent varchar(100) NOT NULL,internal_notes text,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS placement_timeline(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),placement_id uuid NOT NULL,status_change_from varchar(20),status_change_to varchar(20) NOT NULL,status_change_reason text,event_description text NOT NULL,event_type varchar(50),changed_by varchar(100),changed_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS carrier_counter_offers(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),placement_id uuid NOT NULL,proposed_limits jsonb,proposed_premium decimal(12,2),status varchar(20) NOT NULL DEFAULT 'pending',agent_response_date timestamptz,accepted_at timestamptz,rejection_reason text,received_date timestamptz NOT NULL DEFAULT now(),created_at timestamptz NOT NULL DEFAULT now());
